// === Freehandsss V47.19 (2026-07-17 Fat Mo 財務審計：修復吊飾頸鏈成本從未回寫 Total_Cost/Necklace_Cost_Total 的系統性 bug) ===
// 2026-05-23: Rebuilt getItemCategory() — previous version had corrupted CJK chars.
// 2026-05-23: Added '配件' branch for W_WOOL (羊毛氈公仔 - 加購).
// 2026-05-27: Added 燈飾 - 加購 to '配件' branch.
//             '配件' items with cost=0 excluded from zeroCostItems warning.
// 2026-06-02: V47.14 — P0 修正：keychainItemCount 改用 SUM(Original_Qty) 件數
//             而非行數（order_items 行數），對齊 Finance Bible P0 規則。
// 2026-06-03: V47.15 — B2 修正：補入吊飾運費扣減（對稱鎖匙扣邏輯）
//             charmItemCount 累加吊飾件數，扣減 = (charmItemCount-1) × $35
// 2026-06-05: V47.16 — Task A：packedItems 補四分量欄位（前端透傳）
//             + 收斂律自我檢查（SUM毛值−扣減≈Total_Cost，誤差>$1則警告）
// 2026-06-05: V47.17 — 收斂律警告降級：從 zeroCostItems（污染 Has_Cost_Error）
//             改為 n8nAdjustmentNotes（純審計記錄），防止混合訂單（P_MAIN+加購）
//             因 W1 免畫圖導致四分量與 products.total_base_cost 不同源而誤觸
//             Telegram「待核算」假警報。
// 2026-06-26: V47.18 — S124 v2 語義確認（純注釋，無功能改動）
//   products.total_base_cost 已為 per-set 完整成本（fhs_compute_keychain_cost 計算）
//   加購鎖匙扣 N飾：cost=125×N 已存入 DB，n8n 直讀 Total_Base_Cost，無需再×qty
//   Original_Qty（=item_per_set=N飾）僅供 keychainItemCount 累加→運費扣減計算
//   S124 v2 完成：migration 0045(RPC) + 線B products UPDATE + 線C 9單回填 + audit_logs
// 2026-07-17: V47.19 — Fat Mo 全量成本審計發現：products.total_base_cost（吊飾 SKU）
//   從未包含「每2條吊飾共用1條頸鏈$100」規則（Product_Cost_Schema_v2.md necklace_chain_cost
//   key、Finance Bible §6.1 Clasp_Cost 定義），此規則只存在於前端 calculatePricing() 顯示層，
//   從未回寫 DB。全庫抽查 7 張吊飾訂單全部少計，共少記約 $765 成本（利潤報大）。
//   前置修正：migration 0046 已先回填吊飾 SKU total_base_cost（材料成本 365/421→465/465，
//   fhs_compute_charm_cost RPC，仿鎖匙扣 migration 0045 手術，無 clasp/chain 項）——
//   確保本次新增的頸鏈成本不會與舊有凍結值重複計算（fresh-context opus 審查確認）。
//   本版新增：necklaceChainCost = Math.ceil(charmItemCount/2) × $100，獨立於前端 Chain_Cost
//   欄位重新計算（維持 Session 57 B2「n8n 不信任前端成本」原則），計入 Total_Cost 與
//   Necklace_Cost_Total，並寫入 n8nAdjustmentNotes 供審計追溯。
// Reference: .fhs/ai/FHS_Finance_Bible.md §3-4, §G2/G3, S124 v2 cl-flow 2026-06-26-0922
// Reference: .fhs/notes/ai_reports/2026-07-17_order_cost_audit.md（本次修復依據）
// Reference: .fhs/notes/decisions.md D40（2026-07-17 全面追新數簿決策）

const parseNode = $('Parse Items & Generate SKU');
const parseNodeItems = parseNode ? parseNode.all() : [];

if (parseNodeItems.length === 0) {
    return [{ json: { Total_Revenue: 0, Total_Cost: 0, Final_Profit: 0, Sub_Items: [],
        Cost_Lookup_Warning: "", Has_Cost_Error: false,
        Handmodel_Cost_Total: 0, Keychain_Cost_Total: 0, Necklace_Cost_Total: 0,
        N8n_Cost_Adjustments: 0, N8n_Adjustment_Notes: [] } }];
}

const firstNodeData = parseNodeItems[0].json || {};
const totalRevenue = Number(firstNodeData.Total_Revenue) || 0;
const rawFormState = firstNodeData.Raw_Form_State || "";

let deposit = 0, balance = 0, additionalFee = 0;
try {
    const triggerNode = $('Receive Dashboard Order');
    const triggerBody = (triggerNode && triggerNode.first()) ? (triggerNode.first().json.body || triggerNode.first().json) : {};
    deposit = Number(triggerBody.Deposit) || 0;
    balance = Number(triggerBody.Balance) || 0;
    additionalFee = Number(triggerBody.Additional_Fee) || 0;
} catch (error) {}

// SKU → item_category (Finance Bible §3, V47.12)
// Values must match Supabase order_items.item_category exactly.
function getItemCategory(sku) {
    if (!sku) return '其他';
    if (sku.includes('羊毛氈') || sku.includes('燈飾')) return '配件';
    if (sku.includes('木框') || sku.includes('玻璃瓶') || sku.includes('立體擺設')) return '立體擺設';
    if (sku.includes('鎖匙扣')) return '金屬鎖匙扣';
    if (sku.includes('吊飾')) return '純銀頸鏈吊飾';
    return '其他';
}

let totalBaseCost = 0;
let handmodelCostTotal = 0;
let keychainCostTotal = 0;
let necklaceCostTotal = 0;
let packedItems = [];
let keychainItemCount = 0; // P0 修正：累加件數（SUM qty），非行數
let charmItemCount = 0;    // B2：吊飾件數累加（SUM qty）
const zeroCostItems = [];

const items = $input.all();
for (let i = 0; i < parseNodeItems.length; i++) {
    let originalItemData = parseNodeItems[i].json || {};
    let itemData = (items[i] && items[i].json) ? items[i].json : originalItemData;

    let itemCost = Number(itemData.Total_Base_Cost) || 0;
    totalBaseCost += itemCost;

    const sku = originalItemData.Search_SKU || itemData.Search_SKU || "";
    // P0 修正：用 Original_Qty 件數累加，不再用 ++ 行數
    if (sku.includes('鎖匙扣')) {
        keychainItemCount += Number(originalItemData.Original_Qty) || 1;
    }
    // B2：吊飾件數累加（對稱鎖匙扣 P0 修正模式）
    if (sku.includes('吊飾')) {
        charmItemCount += Number(originalItemData.Original_Qty) || 1;
    }

    const itemCategory = getItemCategory(sku);

    // Zero-cost warning: exclude 配件 (intentional $0 service products like W_WOOL / L_LIGHTS)
    if (itemCost === 0 && sku && sku !== '無商品' && sku.trim() !== '' && itemCategory !== '配件') {
        zeroCostItems.push(sku);
    }

    const itemHandmodelCost = itemCategory === '立體擺設'    ? itemCost : 0;
    const itemKeychainCost  = itemCategory === '金屬鎖匙扣'  ? itemCost : 0;
    const itemNecklaceCost  = itemCategory === '純銀頸鏈吊飾' ? itemCost : 0;

    handmodelCostTotal += itemHandmodelCost;
    keychainCostTotal  += itemKeychainCost;
    necklaceCostTotal  += itemNecklaceCost;

    packedItems.push({
        Product_Record_ID: itemData.id || null,
        Product_Name:      itemData.Product_Name || originalItemData.Search_SKU || "Unknown SKU",
        Total_Base_Cost:   itemCost,
        Quantity:          Number(originalItemData.Original_Qty) || 1,
        Notes:             originalItemData.Item_Notes || "",
        Order_Item_Key:    originalItemData.Order_Item_Key || "",
        Item_Category:     itemCategory,
        Handmodel_Cost:    itemHandmodelCost,
        Keychain_Cost:     itemKeychainCost,
        Necklace_Cost:     itemNecklaceCost,
        // Task A: 四分量（前端 calculatePricing() 算好後透傳）
        Drawing_Cost:  Number(originalItemData.Drawing_Cost)  || 0,
        Printing_Cost: Number(originalItemData.Printing_Cost) || 0,
        Chain_Cost:    Number(originalItemData.Chain_Cost)    || 0,
        Shipping_Cost: Number(originalItemData.Shipping_Cost) || 0
    });
}

// 鎖匙扣多件運費折扣 — P0 修正版：件數而非行數 (Finance Bible §2.5 + Session 52 P0)
const keychainShippingDeduction = keychainItemCount > 1 ? (keychainItemCount - 1) * 20 : 0;
totalBaseCost     -= keychainShippingDeduction;
keychainCostTotal -= keychainShippingDeduction;

// 吊飾多件運費折扣 — B2 補入：件數而非行數 (Finance Bible §2.5 + Session 56 B2)
const charmShippingDeduction = charmItemCount > 1 ? (charmItemCount - 1) * 35 : 0;
totalBaseCost     -= charmShippingDeduction;
necklaceCostTotal -= charmShippingDeduction;

// 吊飾頸鏈成本 — V47.19 新增：每 2 條吊飾共用 1 條頸鏈，每條 $100（奇偶進位，Math.ceil）
// (Finance Bible §6.1 Clasp_Cost 定義, Product_Cost_Schema_v2.md necklace_chain_cost key)
// 獨立重算，不信任前端傳入的 Chain_Cost（延續 Session 57 B2「n8n 不信任前端成本」原則）
const necklaceChainCost = charmItemCount > 0 ? Math.ceil(charmItemCount / 2) * 100 : 0;
totalBaseCost     += necklaceChainCost;
necklaceCostTotal += necklaceChainCost;

// V47.17: n8nAdjustmentNotes 移至收斂律檢查之前，使收斂律可推入審計記錄
const n8nAdjustmentNotes = [];
if (keychainShippingDeduction > 0) {
    n8nAdjustmentNotes.push({
        type:                "keychain_shipping_deduction",
        amount:              -keychainShippingDeduction,
        desc:                `${keychainItemCount} 件鎖匙扣同時下單（P0修正：件數非行數），扣減 ${keychainItemCount - 1} 件運費補貼 (每件 $20)`,
        basis:               "Finance Bible §2.5, P0 Session 52",
        keychain_item_count: keychainItemCount
    });
}
if (charmShippingDeduction > 0) {
    n8nAdjustmentNotes.push({
        type:             "charm_shipping_deduction",
        amount:           -charmShippingDeduction,
        desc:             `${charmItemCount} 件吊飾同時下單，扣減 ${charmItemCount - 1} 件運費補貼 (每件 $35)`,
        basis:            "Finance Bible §2.5, B2 Session 56",
        charm_item_count: charmItemCount
    });
}
if (necklaceChainCost > 0) {
    n8nAdjustmentNotes.push({
        type:             "necklace_chain_cost",
        amount:           necklaceChainCost,
        desc:             `${charmItemCount} 條吊飾共用頸鏈，加計 ${Math.ceil(charmItemCount / 2)} 條 × $100（每2條吊飾配1條，奇偶進位）`,
        basis:            "Finance Bible §6.1 Clasp_Cost, Product_Cost_Schema_v2.md necklace_chain_cost, 2026-07-17 審計修正",
        charm_item_count: charmItemCount
    });
}

// Task A: 收斂律自我檢查（§三-B Q1/Q2）
// V47.17 降級：四分量與 products.total_base_cost 不同源（W1 免畫圖等）
// 偏差僅作審計記錄，不污染 zeroCostItems / Has_Cost_Error
const _fourColGross = packedItems.reduce((s, i) =>
    s + (i.Drawing_Cost||0) + (i.Printing_Cost||0) + (i.Chain_Cost||0) + (i.Shipping_Cost||0), 0);
const _fourColNet = _fourColGross - keychainShippingDeduction - charmShippingDeduction;
const _convergenceDiff = Math.abs(_fourColNet - totalBaseCost);
if (_fourColGross > 0 && _convergenceDiff > 1) {
    n8nAdjustmentNotes.push({
        type:   "convergence_note",
        amount: 0,
        desc:   `四分量毛值${_fourColGross}−扣減${keychainShippingDeduction+charmShippingDeduction}=${_fourColNet}，products成本${totalBaseCost}（差${_convergenceDiff.toFixed(2)}，審計用）`,
        basis:  "Task A 收斂律，差值因 W1 免畫圖等不同源屬正常，僅供審計"
    });
}

const n8nCostAdjustments = n8nAdjustmentNotes.reduce((sum, item) => sum + (item.amount || 0), 0);

const finalProfit = totalRevenue - totalBaseCost;
const hasCostError = zeroCostItems.length > 0;
const costLookupWarning = hasCostError
    ? `⚠️ SKU 對不到成本，Total_Cost 可能失真!\n以下項目成本 = $0:\n${zeroCostItems.map(s => `• ${s}`).join('\n')}`
    : "";

return [{
    json: {
        ...firstNodeData,
        Total_Revenue:        totalRevenue,
        Total_Cost:           totalBaseCost,
        Final_Profit:         finalProfit,
        Deposit:              deposit,
        Balance:              balance,
        Additional_Fee:       additionalFee,
        Raw_Form_State:       rawFormState,
        Sub_Items:            packedItems,
        Cost_Lookup_Warning:  costLookupWarning,
        Has_Cost_Error:       hasCostError,
        Handmodel_Cost_Total: handmodelCostTotal,
        Keychain_Cost_Total:  keychainCostTotal,
        Necklace_Cost_Total:  necklaceCostTotal,
        N8n_Cost_Adjustments: n8nCostAdjustments,
        N8n_Adjustment_Notes: n8nAdjustmentNotes
    }
}];
